def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 6:
            for x in range(6, 0, -1):
                for y in range(1, x + 3):
                    factor = ((ratio - x) ** 5) / (x * y * 0.9 + 1)
                    priority += factor * np.cos(ratio * y / (x + 1))
            priority += (np.exp(ratio - 6) * np.sin(ratio * 1.1)) ** 1.5
        elif 3 < ratio <= 6:
            for p in range(1, int(np.ceil(ratio)) + 3):
                for q in range(1, p + 2):
                    term = ((ratio - p) ** 3) * np.sin(ratio * p) / (q + 0.5)
                    priority += np.tanh(term) * 1.2
            priority += np.log(ratio) * 10 - np.tanh(ratio - 3) * 2
        elif 1.5 <= ratio <= 3:
            s = 0
            for r in range(1, 12):
                s += ((ratio - 1.5) ** r) / (r * 1.8) * np.cos(r * ratio)
            priority = (s * np.cos(7 * ratio)) - np.log(ratio) * 6 + np.tanh(4 * (3 - ratio)) * 1.5
        elif 0.8 <= ratio < 1.5:
            s = 0
            for n in range(1, 10):
                s += ((1.5 - ratio) ** n) / (n ** 2 + 0.5)
            if bin_cap < item * 1.1:
                penalty = np.sqrt(item / (bin_cap + 0.5)) * 4
            else:
                penalty = np.cos(20 * ratio) * 2.5
            priority = s + penalty + np.exp(-1.5 / (ratio + 0.05))
            for m in range(1, 5):
                priority += np.sin(m * ratio * i) * ((ratio - 0.8) ** m) / m
        elif 0.3 <= ratio < 0.8:
            s = 0
            for n in range(1, 15):
                s += ((0.8 - ratio) ** n) / (n * 4)
            priority = s
            if (i + int(item * 1.5)) % 4 == 0:
                priority *= np.log1p(bin_cap + 3) * 1.3
            else:
                priority /= (np.sqrt(bin_cap + 1.5) + 2)
            for j in range(1, 6):
                priority += ((0.8 - ratio) ** j) * np.sin(j * item * 1.2) * 0.7
        elif 0.1 <= ratio < 0.3:
            s = 0
            for k in range(1, 12):
                s += ((0.3 - ratio) ** k) / (k * 3) * np.cos(k * ratio * 2)
            priority = s + 1 / (bin_cap + 3)
            if int(item * 1.3) % 4 == 0:
                priority *= 2.5
            else:
                priority /= 2.5
            if bin_cap < item * 0.25:
                priority += np.log1p(item * bin_cap) * 4
            else:
                priority -= np.exp(-ratio * 1.2) * 3
            for m in range(1, 7):
                priority += ((0.3 - ratio) ** m) / (m * 6) * np.cos(item * m * 1.1)
        else:
            s = 0
            for t in range(1, 10):
                s += ((0.1 - ratio) ** t) / (t * 5) * np.sin(t * item * 0.9)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 0.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.15:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 2) * 4
            for u in range(1, 8):
                priority += ((0.1 - ratio) ** u) / (u * 7) * np.cos(item * u * 0.8)
        if bin_cap < item * 0.6:
            priority += np.log1p(item ** 2 * bin_cap) * 5.5
        elif bin_cap > item * 2.5:
            priority -= np.exp(-3 * ratio) * 4
        for idx in range(1, 4):
            if (i + idx) % 3 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.3
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.3
        if i % 3 == 0:
            priority += np.sin(ratio * i * 1.1) * 0.6
        else:
            priority -= np.cos(ratio * i * 1.1) * 0.6
        priorities[i] = priority
    return priorities
